insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'what-is-a-variable', 'What is a variable?', 'Store and label a value so you can use it again later.', 1, 4, 10, '{"introduction":"A variable is a name that points to a value stored in memory. Instead of retyping a value every time you need it, you give it a name once and reuse that name.","explanation":"In Python, you create a variable by writing a name, an equals sign, and a value. There is no need to declare a type up front — Python figures out the type from the value itself. Variable names should describe what they hold: \"age\" is clearer than \"a\", and clarity matters more than brevity once code gets longer than a few lines.","visualExamples":[{"label":"Assigning a number","code":"age = 28"},{"label":"Assigning text","code":"name = \"Maya\""},{"label":"Reassigning later","code":"age = 29"}],"codeExample":{"code":"name = \"Maya\"\nage = 28\nprint(name)\nprint(age)","expectedOutput":"Maya\n28"},"commonMistakes":[{"mistake":"Using a number as the first character of a variable name, like 1st_try = 5.","why":"Python variable names can’t start with a digit. Start with a letter or underscore instead, e.g. first_try."},{"mistake":"Forgetting that variable names are case-sensitive.","why":"age and Age are two completely different variables to Python, which is a common source of confusing bugs."}],"tips":["Use snake_case for variable names in Python (lowercase words separated by underscores) — it’s the convention nearly all Python code follows.","Pick names that describe the value’s purpose, not its type. total is better than my_int."],"quiz":[{"question":"Which of these is a valid Python variable name?","options":["2nd_place","second_place","second-place","second place"],"correctIndex":1,"explanation":"Variable names can’t start with a digit, and can’t contain hyphens or spaces — underscores are used instead."}],"summary":"A variable is a named reference to a value. Create one with name = value, and Python infers the type automatically."}'::jsonb
