select id, 'arithmetic-operators', 'Arithmetic operators', 'Add, subtract, multiply, divide, and a few less obvious ones.', 1, 5, 10, '{"introduction":"Arithmetic operators do math: +, -, *, /, and a couple of operators that aren’t in basic math class but come up constantly in code.","explanation":"Beyond the four you already know, Python has // (floor division, which divides and drops the remainder), % (modulo, which gives just the remainder), and ** (exponent, for powers). Regular division (/) always returns a float, even when dividing evenly — 10 / 2 gives 5.0, not 5.","visualExamples":[{"label":"Floor division","code":"17 // 5"},{"label":"Modulo (remainder)","code":"17 % 5"},{"label":"Exponent","code":"2 ** 5"}],"codeExample":{"code":"a = 17\nb = 5\n\nprint(a / b)\nprint(a // b)\nprint(a % b)\nprint(a ** 2)","expectedOutput":"3.4\n3\n2\n289"},"commonMistakes":[{"mistake":"Using ^ for exponents, like 2 ^ 5.","why":"In Python, ^ is a different operator entirely (bitwise XOR). Use ** for powers: 2 ** 5."},{"mistake":"Expecting / to always give a whole number when dividing evenly.","why":"/ always returns a float in Python 3. If you specifically need a whole-number result, use // instead."}],"tips":["% is the operator to reach for when you need to check \"is this number even?\" — a number is even if number % 2 == 0.","Order of operations follows standard math rules: ** before * and /, which come before + and -."],"quiz":[{"question":"What does 10 % 3 evaluate to?","options":["3","3.33","1","0"],"correctIndex":2,"explanation":"10 divided by 3 is 3 with a remainder of 1 — % returns just that remainder."}],"summary":"Beyond +, -, *, /, Python has // (floor division), % (remainder), and ** (exponent). Regular division always returns a float."}'::jsonb
