insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'operator-precedence', 'Operator precedence', 'Which operators run first when an expression has several.', 3, 4, 10, '{"introduction":"When an expression has multiple operators, Python evaluates them in a specific order — the same general order you learned in math class, extended to cover Python’s extra operators.","explanation":"From highest to lowest priority: parentheses first, then ** (exponent), then * / // % (multiplication-family), then + - (addition-family), then comparisons, then logical operators (not, then and, then or). When in doubt, parentheses always win and make intent clearer to a reader, even when they aren’t strictly required.","visualExamples":[{"label":"Without parentheses","code":"2 + 3 * 4"},{"label":"With parentheses","code":"(2 + 3) * 4"},{"label":"Mixed operators","code":"10 - 2 ** 2"}],"codeExample":{"code":"result_a = 2 + 3 * 4\nresult_b = (2 + 3) * 4\nresult_c = 10 - 2 ** 2\n\nprint(result_a)\nprint(result_b)\nprint(result_c)","expectedOutput":"14\n20\n6"},"commonMistakes":[{"mistake":"Assuming Python evaluates strictly left to right, ignoring operator priority.","why":"2 + 3 * 4 is 14, not 20 — multiplication runs before addition regardless of left-to-right order in the text."},{"mistake":"Skipping parentheses in a complex condition and getting unexpected logic.","why":"a or b and c evaluates \"and\" before \"or\", which may not match what you intended. Parenthesize to be explicit: a or (b and c)."}],"tips":["When precedence rules might be unclear to a future reader (including future you), add parentheses even if they’re not required — clarity beats cleverness.","If a calculation gives a surprising result, print() each sub-part separately to see where the order of operations diverged from your expectation."],"quiz":[{"question":"What does 4 + 2 ** 2 evaluate to?","options":["36","8","12","16"],"correctIndex":1,"explanation":"** runs before +, so this is 4 + (2 ** 2) = 4 + 4 = 8."}],"summary":"Python follows a fixed order of operations: parentheses, then **, then * / // %, then + -, then comparisons, then logical operators. Use parentheses to make intent explicit."}'::jsonb
