insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'if-elif-else', 'if, elif, else', 'Make your code run different paths depending on a condition.', 1, 5, 15, '{"introduction":"An if statement runs a block of code only when a condition is true. elif and else let you handle additional conditions and a fallback case.","explanation":"The structure is: if condition:, then an indented block that runs if the condition is true. elif (else if) checks another condition only if the previous ones were false. else catches everything not already handled. Python uses indentation — not curly braces — to mark which lines belong to which block, so consistent indentation is not optional, it’s part of the syntax.","visualExamples":[{"label":"Simple if","code":"if age >= 18:\n    print(\"Adult\")"},{"label":"if/else","code":"if age >= 18:\n    print(\"Adult\")\nelse:\n    print(\"Minor\")"}],"codeExample":{"code":"score = 75\n\nif score >= 90:\n    print(\"A\")\nelif score >= 80:\n    print(\"B\")\nelif score >= 70:\n    print(\"C\")\nelse:\n    print(\"F\")","expectedOutput":"C"},"commonMistakes":[{"mistake":"Forgetting the colon at the end of the if line.","why":"Python requires a colon to mark the start of the indented block — if score >= 90 without the colon is a syntax error."},{"mistake":"Inconsistent indentation, mixing tabs and spaces, or different indent widths in the same block.","why":"Since indentation IS the syntax in Python, mismatched indentation raises an IndentationError. Stick to one style (4 spaces is the near-universal convention) throughout a file."}],"tips":["Only the first matching condition in an if/elif chain runs — once one matches, Python skips the rest, even if a later condition would also be true.","If you only have two outcomes, you usually only need if/else — save elif for when there are genuinely three or more distinct paths."],"quiz":[{"question":"In an if/elif/else chain, how many blocks can run for a single check?","options":["Only one — the first matching condition","All matching conditions","Only the else block","It depends on the order"],"correctIndex":0,"explanation":"Python stops checking after the first true condition in the chain and runs only that block."}],"summary":"if/elif/else let code branch based on conditions. Indentation marks each block — it’s required syntax, not just style."}'::jsonb
