insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'for-loops', 'for loops', 'Repeat code once for each item in a sequence.', 3, 5, 15, '{"introduction":"A for loop runs a block of code once for each item in a sequence — like each character in a string, or each number in a range. It’s the most common loop in everyday Python.","explanation":"The structure is for variable in sequence:, where \"variable\" takes on each value in \"sequence\", one at a time. range() is the most common sequence to loop over when you want to repeat something a specific number of times: range(5) produces 0, 1, 2, 3, 4 — five values, starting at 0.","visualExamples":[{"label":"Looping over a range","code":"for i in range(3):\n    print(i)"},{"label":"Looping over a string","code":"for letter in \"Hi\":\n    print(letter)"}],"codeExample":{"code":"for i in range(5):\n    print(i * 2)","expectedOutput":"0\n2\n4\n6\n8"},"commonMistakes":[{"mistake":"Expecting range(5) to include 5.","why":"range(5) produces 0 through 4 — five numbers total, but stopping just before 5. range(start, stop) works the same way: the stop value is never included."},{"mistake":"Trying to modify a list while looping over it directly.","why":"Changing a sequence’s length while iterating over it can skip items or cause errors. This is a more advanced pitfall worth knowing about even before you hit it."}],"tips":["range(start, stop, step) lets you control where the loop begins, ends, and how much it increases each time — e.g. range(0, 10, 2) gives even numbers 0 through 8.","If you need both the index and the value while looping, enumerate() is the idiomatic tool — you’ll meet it once lists are covered."],"quiz":[{"question":"How many times does the loop body run for `for i in range(4):`?","options":["3","4","5","It depends on i"],"correctIndex":1,"explanation":"range(4) produces 0, 1, 2, 3 — four values — so the loop body runs exactly four times."}],"summary":"for loops repeat once per item in a sequence. range() generates a sequence of numbers, commonly used to repeat something a fixed number of times."}'::jsonb
