insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'break-and-continue', 'break & continue', 'Exit a loop early, or skip to the next iteration.', 4, 4, 15, '{"introduction":"break stops a loop immediately, regardless of its condition. continue skips the rest of the current iteration and moves on to the next one.","explanation":"Both work inside for and while loops. break is useful for \"stop searching once you’ve found what you need\" patterns. continue is useful for \"skip this particular item, but keep going\" patterns — like skipping over values that don’t meet some criteria without exiting the loop entirely.","visualExamples":[{"label":"Stopping early","code":"for n in range(10):\n    if n == 5:\n        break\n    print(n)"},{"label":"Skipping an item","code":"for n in range(5):\n    if n == 2:\n        continue\n    print(n)"}],"codeExample":{"code":"for n in range(10):\n    if n == 5:\n        break\n    if n % 2 == 0:\n        continue\n    print(n)","expectedOutput":"1\n3"},"commonMistakes":[{"mistake":"Using break when continue was actually intended, or vice versa.","why":"break exits the entire loop; continue only skips the current pass and keeps looping. Mixing them up either ends a loop too early or never skips the item you meant to skip."},{"mistake":"Putting break or continue outside of any loop.","why":"Both only make sense inside a for or while loop — using them elsewhere raises a SyntaxError."}],"tips":["Trace through the example above mentally, one number at a time, if the output isn’t immediately obvious — this is one of the few lessons worth stepping through by hand.","A loop with break is often paired with else on the loop itself (an intermediate-level pattern) to detect \"did we ever find it?\" — worth knowing exists, even if you don’t need it yet."],"quiz":[{"question":"What does continue do inside a loop?","options":["Stops the loop completely","Skips the rest of the current iteration and moves to the next one","Restarts the loop from the beginning","Pauses the loop"],"correctIndex":1,"explanation":"continue jumps straight to the next iteration, skipping any remaining code in the current pass — it does not exit the loop."}],"summary":"break exits a loop immediately. continue skips to the next iteration without exiting. Both only work inside a loop."}'::jsonb
