insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'defining-functions', 'Defining functions', 'Package a block of code so you can reuse it by name.', 1, 5, 15, '{"introduction":"A function is a named, reusable block of code. Instead of copying the same lines everywhere you need them, you define the logic once and \"call\" it by name whenever you need it.","explanation":"Define a function with def name():, followed by an indented block — the same indentation rule as if statements and loops. You \"call\" (run) the function later by writing its name followed by parentheses. Functions don’t run when defined; they only run when called.","visualExamples":[{"label":"Defining a function","code":"def greet():\n    print(\"Hello!\")"},{"label":"Calling it","code":"greet()"}],"codeExample":{"code":"def greet():\n    print(\"Hello!\")\n\nprint(\"Before calling\")\ngreet()\nprint(\"After calling\")","expectedOutput":"Before calling\nHello!\nAfter calling"},"commonMistakes":[{"mistake":"Forgetting the parentheses when calling a function, like greet instead of greet().","why":"Without parentheses, you’re referring to the function itself, not running it — nothing happens, and no error is raised, which makes this an easy mistake to miss."},{"mistake":"Expecting code in a function to run immediately when it’s defined.","why":"def only creates the function — the code inside only runs once you actually call it later with greet()."}],"tips":["Function names should be verbs or verb phrases describing what they do — calculate_total, send_email, not just data or stuff.","You can define a function anywhere above where you call it, but it’s conventional to group all function definitions near the top of a file."],"quiz":[{"question":"What happens when Python runs a \"def\" line by itself, without calling the function?","options":["The function body runs immediately","The function is defined but its body doesn’t run yet","A syntax error occurs","Nothing is created"],"correctIndex":1,"explanation":"def only creates the function in memory — the body inside only executes once you call the function by name with parentheses."}],"summary":"def name(): defines a reusable block of code. The block only runs when you call the function by name with parentheses."}'::jsonb
