insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'parameters-and-return-values', 'Parameters & return values', 'Pass information into a function, and get a result back out.', 2, 6, 20, '{"introduction":"Parameters let a function accept input. return lets a function send a result back to wherever it was called from, instead of just printing something directly.","explanation":"Parameters go inside the parentheses in the function definition, and become local variables inside the function. When calling the function, you provide matching \"arguments\" — the actual values. return ends the function and hands back a value, which you can then store in a variable or use right away. A function without an explicit return implicitly returns None.","visualExamples":[{"label":"A parameter","code":"def greet(name):\n    print(f\"Hello, {name}!\")"},{"label":"A return value","code":"def add(a, b):\n    return a + b"}],"codeExample":{"code":"def add(a, b):\n    return a + b\n\nresult = add(3, 4)\nprint(result)\nprint(add(10, 20))","expectedOutput":"7\n30"},"commonMistakes":[{"mistake":"Using print() inside a function when the caller actually needs the value back via return.","why":"print() only displays a value — it doesn’t hand it back to the rest of the program. If you write result = add(3, 4) but add() only prints, result ends up being None."},{"mistake":"Calling a function with the wrong number of arguments.","why":"If a function is defined with two parameters, like def add(a, b), calling add(3) (only one argument) raises a TypeError — Python requires every parameter to get a value unless it has a default."}],"tips":["You can give a parameter a default value, like def greet(name=\"friend\"):, making the argument optional when calling it.","A function can return multiple values at once, separated by commas — Python packages them together automatically, a feature worth knowing exists even before you need it."],"quiz":[{"question":"What does a function return if it has no explicit return statement?","options":["0","An empty string","None","It raises an error"],"correctIndex":2,"explanation":"Without an explicit return, Python functions implicitly return None when they finish running."}],"summary":"Parameters accept input when a function is called. return sends a result back to the caller — without it, the function returns None."}'::jsonb
