insert into public.lessons (module_id, slug, title, summary, sort_order, estimated_minutes, xp_reward, content)
select id, 'scope-basics', 'Scope basics', 'Where a variable exists, and where it doesn’t.', 3, 5, 20, '{"introduction":"Scope determines where in your code a variable can be used. A variable created inside a function generally only exists inside that function.","explanation":"Variables defined inside a function are \"local\" — they exist only while that function is running, and disappear once it finishes. Variables defined outside any function, at the top level of a file, are \"global\" and can be read from inside functions, though modifying a global variable from inside a function needs the \"global\" keyword (an edge case you’ll rarely need early on).","visualExamples":[{"label":"A local variable","code":"def calculate():\n    total = 10\n    return total"},{"label":"Trying to use it outside","code":"calculate()\nprint(total)  # Error: total doesn’t exist here"}],"codeExample":{"code":"def calculate():\n    total = 10\n    return total\n\nresult = calculate()\nprint(result)","expectedOutput":"10"},"commonMistakes":[{"mistake":"Trying to access a function’s local variable from outside that function.","why":"Local variables only exist while their function is running. Once the function returns, they’re gone — only the returned value (if any) survives."},{"mistake":"Assuming two functions can’t use the same variable name without conflict.","why":"Actually the opposite is true and is often a source of confusion the other way: each function has its own separate local scope, so reusing a name like total in two different functions is completely safe and won’t cause a clash."}],"tips":["If you find yourself needing a function to permanently change a variable outside itself, consider having it return the new value instead — it’s usually clearer than relying on global state.","When debugging a \"variable not defined\" error, check whether the variable was created inside a function that already finished running."],"quiz":[{"question":"What happens to a local variable once its function finishes running?","options":["It becomes global","It keeps its last value forever","It stops existing","It resets to None"],"correctIndex":2,"explanation":"Local variables exist only for the duration of the function call — once the function returns, they’re gone entirely."}],"summary":"Variables created inside a function are local and disappear once the function finishes. Variables at the top level of a file are global and readable from inside functions."}'::jsonb
